if(!$d){header('Location: admin-dispatch-advices.php?message=Document not found');exit;}if(in_array($a,['save','finalize'],true)){if($d['status']!=='draft'){header('Location: admin-dispatch-advices.php?message=Create a revision to change a finalized document');exit;}$d['planned_dispatch_date']=safe_text($_POST['planned_dispatch_date']??'');$d['delivery_address']=safe_text($_POST['delivery_address']??'');$d['customer_note']=safe_text($_POST['customer_note']??'');$d['items']=documents_normalize_dispatch_advice_items(array_map(null,$_POST['name']??[],$_POST['description']??[], $_POST['brand_model']??[],$_POST['qty']??[],$_POST['unit']??[],$_POST['remarks']??[],$_POST['catalog_item_id']??[],$_POST['line_id']??[]));if($a==='finalize'){$v=documents_validate_dispatch_advice($d);if(empty($v['ok'])){header('Location: admin-dispatch-advices.php?edit='.urlencode($d['id']).'&message='.urlencode($v['error']));exit;}}$d['status']=$a==='finalize'?'finalized':'draft';}
if($a==='share_toggle'){$d['public_share_enabled']=!$d['public_share_enabled'];if(!$d['public_token'])$d['public_token']=bin2hex(random_bytes(32));}
